        .putBoolean(KEY_WHISPER_ACTIVE, false)
        .apply()
}

fun setPackageAlarm(ctx: Context, hours: Double) {
    val triggerAt = System.currentTimeMillis() + (hours * 3600000).toLong() - (5 * 60000)
    ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE).edit()
        .putLong(KEY_PACKAGE_ALARM_TS, triggerAt)
        .apply()
}

fun checkPackageAlarm(ctx: Context) {
    val prefs = ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
    val triggerAt = prefs.getLong(KEY_PACKAGE_ALARM_TS, 0L)
    if (triggerAt > 0 && System.currentTimeMillis() >= triggerAt) {
        // Fire Notification
        val nm = ctx.getSystemService(Context.NOTIFICATION_SERVICE) as android.app.NotificationManager
        val channelId = "package_alerts"
        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
            val chan = android.app.NotificationChannel(channelId, "Package Alerts", android.app.NotificationManager.IMPORTANCE_HIGH)
            nm.createNotificationChannel(chan)
        }
        val builder = androidx.core.app.NotificationCompat.Builder(ctx, channelId)
            .setSmallIcon(android.R.drawable.ic_dialog_info)
            .setContentTitle("PACKAGE UPDATE")
            .setContentText("your package is running out,buy new one.")
            .setPriority(androidx.core.app.NotificationCompat.PRIORITY_HIGH)
            .setAutoCancel(true)
        nm.notify(777, builder.build())

        // Clear Alarm
        prefs.edit().remove(KEY_PACKAGE_ALARM_TS).apply()
    }
}

