private fun scheduleAlarm(ctx: Context, h: Int, m: Int, wake: Boolean) {
    val am = ctx.getSystemService(Context.ALARM_SERVICE) as android.app.AlarmManager
    val intent = Intent(ctx, AlarmReceiver::class.java).apply {
        putExtra("WAKE_ME_UP", wake)
    }
    val pi = android.app.PendingIntent.getBroadcast(ctx, 0, intent, android.app.PendingIntent.FLAG_UPDATE_CURRENT or android.app.PendingIntent.FLAG_IMMUTABLE)

    val calendar = java.util.Calendar.getInstance().apply {
        set(java.util.Calendar.HOUR_OF_DAY, h)
        set(java.util.Calendar.MINUTE, m)
        set(java.util.Calendar.SECOND, 0)
        if (before(java.util.Calendar.getInstance())) add(java.util.Calendar.DATE, 1)
    }

    if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.M) {
        am.setExactAndAllowWhileIdle(android.app.AlarmManager.RTC_WAKEUP, calendar.timeInMillis, pi)
    } else {
        am.setExact(android.app.AlarmManager.RTC_WAKEUP, calendar.timeInMillis, pi)
    }
    android.widget.Toast.makeText(ctx, "Alarm set for ${h}:${m}", android.widget.Toast.LENGTH_SHORT).show()
}

