private fun scheduleSystemAlarm(ctx: Context, alarm: LockManager.GuardianAlarm) {
    if (!alarm.isEnabled) return
    val am = ctx.getSystemService(Context.ALARM_SERVICE) as android.app.AlarmManager
    val intent = Intent(ctx, AlarmReceiver::class.java).apply {
        putExtra("WAKE_ME_UP", alarm.isWakeMeUp)
        putExtra("ALARM_ID", alarm.id)
    }
    // Hash the ID string to get a unique int request code
    val requestCode = alarm.id.hashCode()
    val pi = android.app.PendingIntent.getBroadcast(ctx, requestCode, intent, android.app.PendingIntent.FLAG_UPDATE_CURRENT or android.app.PendingIntent.FLAG_IMMUTABLE)

    val calendar = java.util.Calendar.getInstance().apply {
        set(java.util.Calendar.HOUR_OF_DAY, alarm.hour)
        set(java.util.Calendar.MINUTE, alarm.minute)
        set(java.util.Calendar.SECOND, 0)
        if (before(java.util.Calendar.getInstance())) add(java.util.Calendar.DATE, 1)
    }

    if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.M) {
        am.setExactAndAllowWhileIdle(android.app.AlarmManager.RTC_WAKEUP, calendar.timeInMillis, pi)
    } else {
        am.setExact(android.app.AlarmManager.RTC_WAKEUP, calendar.timeInMillis, pi)
    }
}

private fun cancelSystemAlarm(ctx: Context, alarmId: String) {
    val am = ctx.getSystemService(Context.ALARM_SERVICE) as android.app.AlarmManager
    val intent = Intent(ctx, AlarmReceiver::class.java)
    val pi = android.app.PendingIntent.getBroadcast(ctx, alarmId.hashCode(), intent, android.app.PendingIntent.FLAG_NO_CREATE or android.app.PendingIntent.FLAG_IMMUTABLE)
    if (pi != null) am.cancel(pi)
}

private fun updateAlarmState(ctx: Context, alarm: LockManager.GuardianAlarm, enabled: Boolean, onUpdate: () -> Unit) {
    val list = LockManager.getAlarms(ctx).toMutableList()
    val index = list.indexOfFirst { it.id == alarm.id }
    if (index != -1) {
        val updated = list[index].copy(isEnabled = enabled)
        list[index] = updated
        LockManager.saveAlarms(ctx, list)
        if (enabled) scheduleSystemAlarm(ctx, updated) else cancelSystemAlarm(ctx, alarm.id)
        onUpdate()
    }
}

private fun deleteAlarm(ctx: Context, alarm: LockManager.GuardianAlarm, onUpdate: () -> Unit) {
    val list = LockManager.getAlarms(ctx).filter { it.id != alarm.id }
    LockManager.saveAlarms(ctx, list)
    cancelSystemAlarm(ctx, alarm.id)
    onUpdate()
}

