fun isWhisperAlarm(ctx: Context): Boolean = ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE).getBoolean(KEY_WHISPER_ALARM_EXTENDED, false)

data class GuardianAlarm(
    val id: String = java.util.UUID.randomUUID().toString(),
    val hour: Int,
    val minute: Int,
    val label: String = "Alarm",
    val isEnabled: Boolean = true,
    val isWakeMeUp: Boolean = true
)

fun getAlarms(ctx: Context): List<GuardianAlarm> {
    val json = ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE).getString(KEY_ALARMS_JSON, "[]")
    return try {
        val array = org.json.JSONArray(json)
        val list = mutableListOf<GuardianAlarm>()
        for (i in 0 until array.length()) {
            val obj = array.getJSONObject(i)
            list.add(GuardianAlarm(
                obj.getString("id"),
                obj.getInt("hour"),
                obj.getInt("minute"),
                obj.getString("label"),
                obj.getBoolean("isEnabled"),
                obj.getBoolean("isWakeMeUp")
            ))
        }
        list.sortedWith(compareBy({ it.hour }, { it.minute }))
    } catch (e: Exception) { emptyList() }
}

fun saveAlarms(ctx: Context, alarms: List<GuardianAlarm>) {
    val array = org.json.JSONArray()
    alarms.forEach {
        val obj = org.json.JSONObject()
        obj.put("id", it.id)
        obj.put("hour", it.hour)
        obj.put("minute", it.minute)
        obj.put("label", it.label)
        obj.put("isEnabled", it.isEnabled)
        obj.put("isWakeMeUp", it.isWakeMeUp)
        array.put(obj)
    }
    ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE).edit()
        .putString(KEY_ALARMS_JSON, array.toString()).apply()
}

